function parseCsvLine(line) {
  const vals = []; let inQuote = false, cur = '';
  for (const ch of line) {
    if (ch === '"') inQuote = !inQuote;
    else if (ch === ',' && !inQuote) { vals.push(cur.trim()); cur = ''; }
    else cur += ch;
  }
  vals.push(cur.trim()); return vals;
}
const raw = $input.first().json.data || '';
const lines = raw.split('\n').filter(l => l.trim());
const rows = lines.slice(1).map(parseCsvLine);
function isShopifyPosted(status, blogUrl) {
  const s = (status || '').toLowerCase().trim();
  const url = (blogUrl || '').trim();
  if (url.includes('waxandwane.store') || url.includes('myshopify.com')) return true;
  if (s.includes('shopify') || s.startsWith('done:') || s === 'published') return true;
  return false;
}
for (let i = 0; i < rows.length; i++) {
  const row = rows[i];
  const title = (row[0] || '').trim();
  const keywords = (row[1] || '').trim();
  const status = (row[4] || '').trim();
  const blogUrl = (row[6] || '').trim();
  let docUrl = (row[8] || '').trim();
  const docId = (row[7] || '').trim();
  if (!title) continue;
  if (status.toLowerCase() !== 'drafted') continue;
  if (isShopifyPosted(status, blogUrl)) continue;
  if (!docUrl && docId) docUrl = 'https://docs.google.com/document/d/' + docId + '/edit';
  if (!docUrl.includes('docs.google.com')) continue;
  const idMatch = docUrl.match(/\/d\/([a-zA-Z0-9_-]+)/);
  const googleDocId = idMatch ? idMatch[1] : docId;
  return [{ json: { rowIndex: i + 2, title, keywords, docUrl, googleDocId, pipeline: 'manus-google-doc' } }];
}
return [{ json: { rowIndex: -1, message: 'No Drafted rows pending Shopify' } }];

const text = ($input.first().json.data || '').replace(/\s+/g, ' ').trim();
const findRow = $('Find Next Source Row').first().json;
if (text.length < 100) throw new Error('Google Doc export empty — check OAuth access');
return [{ json: { extractedText: text.substring(0, 12000), title: findRow.title, keywords: findRow.keywords, sourceUrl: findRow.docUrl, topic: findRow.title } }];

