const pplx = $input.first().json;
let blogHtml = pplx.choices[0].message.content;
blogHtml = blogHtml.replace(/^```html\s*/i,'').replace(/^```\s*/i,'').replace(/\s*```$/i,'').trim();
const findRow = $('Find Next Source Row').first().json;
const titleMatch = blogHtml.match(/<h1[^>]*>(.*?)<\/h1>/i);
const title = titleMatch ? titleMatch[1].replace(/<[^>]+>/g,'').trim() : (findRow.title || findRow.topic);
const handle = title.toLowerCase().replace(/[^a-z0-9\s-]/g,'').replace(/\s+/g,'-').replace(/^-+|-+$/g,'').substring(0,60);
const stripped = blogHtml.replace(/<[^>]+>/g,' ').replace(/\s+/g,' ').trim();
return [{ json: { title, handle, body_html: blogHtml, metaDescription: stripped.substring(0,160), keywords: findRow.keywords || findRow.topic, sourceUrl: findRow.sourceUrl || findRow.docUrl, rowIndex: findRow.rowIndex, caption: `New on the Wax & Wane blog: "${title}"\n\nwaxandwane.store/blogs/wax-wane-blog/${handle}` } }];

